import './Breadcrumbs.scss';

import { classNames } from ':helpers/classnames';
import type { FC } from 'react';
import React, { useCallback, useEffect, useRef, useState } from 'react';

import type { BreadcrumbsProps } from './Breadcrumbs.types';
import { BreadcrumbsItem } from './BreadcrumbsItem';
import { renderChildren } from './render-children';

export const Breadcrumbs: FC<BreadcrumbsProps> = ({ children, collapsed = false, className, value }) => {
	const [isCollapsed, setCollapsed] = useState<boolean>(collapsed);

	const handleClickAway = useCallback((): void => {
		collapsed && setCollapsed(true);
	}, [collapsed, setCollapsed]);

	const handleClickDots = (): void => {
		setCollapsed(false);
	};

	const navRef = useRef(null);

	useEffect(() => {
		const handleClickOutside = (event: MouseEvent): void => {
			if (navRef.current && !document.contains.call(navRef.current, event.target)) {
				handleClickAway();
			}
		};
		document.addEventListener('mousedown', handleClickOutside);
		return () => {
			document.removeEventListener('mousedown', handleClickOutside);
		};
	}, [navRef, handleClickAway]);

	const renderValueIntoChildren = value => {
		const children = value.map((item, index) => <BreadcrumbsItem {...item} index={index} />);
		return renderChildren(children, isCollapsed, handleClickDots);
	};

	const content = value ? renderValueIntoChildren(value) : renderChildren(children, isCollapsed, handleClickDots);
	return (
		<nav
			data-testid="Breadcrumbs"
			ref={navRef}
			className={classNames(className, 'dsb-breadcrumbs')}
			aria-label="Breadcrumb"
			itemScope
			itemType="https://schema.org/BreadcrumbList "
		>
			<ul className="dsb-breadcrumbs__list">{content}</ul>
		</nav>
	);
};
